export const SNIPPETS: Record<string, string> = {
  "alloc.h": "/* mtoc runtime helper: malloc wrapper that aborts on allocation\n * failure with a clear diagnostic. Used for every tensor backing\n * buffer (mtoc allocates tensor storage uniformly on the heap so the\n * codegen path is exercised by every test, not just large ones).\n *\n * `n_bytes` is the size in bytes; the call site computes\n * `numel * sizeof(double)`. Returns a non-NULL pointer or aborts.\n */\n\n#include <stdio.h>\n#include <stdlib.h>\n\nstatic double *mtoc2_alloc(size_t n_bytes) {\n  /* `malloc(0)` is implementation-defined: glibc returns a non-NULL\n   * sentinel, but some C libraries return NULL — which would trip\n   * the OOM abort below on a perfectly valid empty-tensor request.\n   * Clamp to a 1-byte allocation so the contract \"return non-NULL or\n   * abort on OOM\" holds uniformly. The caller never reads from a\n   * zero-element buffer, so the wasted byte is irrelevant. */\n  double *p = (double *)malloc(n_bytes == 0 ? 1 : n_bytes);\n  if (!p) {\n    fprintf(stderr, \"mtoc2: out of memory (mtoc2_alloc requested %zu bytes)\\n\",\n            n_bytes);\n    abort();\n  }\n  return p;\n}\n",
  "assert_fail.h": "/* mtoc2 runtime helper: scalar `assert(cond, msg)`. Tests `cond` for\n * MATLAB truthiness (non-zero and not NaN); fires `abort()` after\n * printing the message to stderr if the test fails.\n *\n * Numbl's `assert` (`interpreter/builtins/utility.ts:151`) accepts\n * tensor conds too — every element must be non-zero and not NaN. We\n * only support scalar conds in v1 (chunkie_simple's `assert(n >= 0,\n * ...)` is scalar-comparison-result anyway). Tensor-cond support is\n * a small followup.\n *\n * `msg` may be NULL or empty; the printer falls back to a generic\n * \"assertion failed\" line in that case.\n */\n#include <stdio.h>\n#include <stdlib.h>\n\nstatic void mtoc2_assert_scalar(double cond, const char *msg) {\n  /* `cond != cond` filters NaN — numbl's `isNaN(v)` check. */\n  if (cond != 0.0 && cond == cond) return;\n  fputs(\"mtoc2: assertion failed\", stderr);\n  if (msg != NULL && msg[0] != '\\0') {\n    fputs(\": \", stderr);\n    fputs(msg, stderr);\n  }\n  fputc('\\n', stderr);\n  abort();\n}\n",
  "disp_double.h": "/* mtoc runtime helper: disp(x) for a real-scalar double.\n *\n * Mirrors numbl's `formatNumber` (numbl/src/numbl-core/runtime/display.ts)\n * so cross-runner test output matches. The actual formatting lives in\n * `format_double.h`; this snippet only wraps it with a print + newline.\n */\n\n#include <stdio.h>\n\nstatic void mtoc2_disp_double(double x) {\n  char buf[64];\n  mtoc2_format_double(buf, sizeof(buf), x);\n  printf(\"%s\\n\", buf);\n}\n",
  "disp_tensor.h": "/* mtoc runtime helper: disp(t) for a multi-element real tensor.\n *\n * Mirrors numbl's `format2DSlice` for the 2-D path and numbl's\n * page-by-page N-D rendering for `ndim > 2` (each 2-D slice prefixed\n * by a `(:,:,k2,k3,...) =` header and separated by a blank line):\n *   - elements are formatted via mtoc2_format_double\n *   - each column is padded to its widest element via padStart\n *   - rows are separated by '\\n', columns by 3 spaces, 3-space indent\n *\n * Allocation: per-slice malloc for the formatted-string buffer and\n * column-width array. Both freed before the next slice. The disp\n * path is not on the hot path of typical numerical code, so the\n * simplicity is worth the alloc.\n *\n * Real-only — complex-tensor disp lives in `disp_tensor_complex.h`;\n * the lowerer dispatches on `isComplex`.\n */\n\n#include <stdio.h>\n#include <stdlib.h>\n#include <string.h>\n\n/* Render a single 2-D slice (rows × cols) starting at `data` (the\n * caller already advanced past prior pages). Each row ends with\n * '\\n'; no leading or trailing framing — the caller adds page\n * headers / separators. */\nstatic void mtoc2__disp_real_slice(const double *data, long rows, long cols) {\n  enum { CELL_CAP = 32 };\n  long ncells = rows * cols;\n  char *cells = (char *)malloc((size_t)ncells * CELL_CAP);\n  long *col_widths = (long *)calloc((size_t)cols, sizeof(long));\n  if (!cells || !col_widths) {\n    free(cells);\n    free(col_widths);\n    fprintf(stderr, \"mtoc2: out of memory in mtoc2_disp_tensor\\n\");\n    return;\n  }\n\n  for (long c = 0; c < cols; c++) {\n    for (long r = 0; r < rows; r++) {\n      long idx = r + c * rows;\n      char *cell = cells + idx * CELL_CAP;\n      mtoc2_format_double(cell, CELL_CAP, data[idx]);\n      long len = (long)strlen(cell);\n      if (len > col_widths[c]) col_widths[c] = len;\n    }\n  }\n\n  for (long r = 0; r < rows; r++) {\n    fputs(\"   \", stdout);\n    for (long c = 0; c < cols; c++) {\n      long idx = r + c * rows;\n      char *cell = cells + idx * CELL_CAP;\n      long len = (long)strlen(cell);\n      for (long i = 0; i < col_widths[c] - len; i++) putchar(' ');\n      fputs(cell, stdout);\n      if (c < cols - 1) fputs(\"   \", stdout);\n    }\n    putchar('\\n');\n  }\n\n  free(cells);\n  free(col_widths);\n}\n\nstatic void mtoc2_disp_tensor(mtoc2_tensor_t t) {\n  if (t.ndim == 0 || t.real == NULL) {\n    /* `mtoc2_tensor_empty()` placeholder. Reaches here when a\n     * conditionally-assigned tensor is `disp`ed on a path the\n     * conditional didn't fire. Numbl's `disp` short-circuits empty\n     * tensors silently (specialBuiltins.ts: the disp handler\n     * returns before printing if `data.length === 0`), so we\n     * print nothing here too. */\n    return;\n  }\n  long rows = t.ndim >= 1 ? t.dims[0] : 1;\n  long cols = t.ndim >= 2 ? t.dims[1] : 1;\n  long total = 1;\n  for (int i = 0; i < t.ndim; i++) total *= t.dims[i];\n  if (total <= 0) {\n    /* Empty tensor — numbl's `disp` prints nothing (it bails on\n     * `data.length === 0` before reaching the formatter). The\n     * `[]` rendering from `formatTensor` is only used by other\n     * surface forms (string cast, struct field display). */\n    return;\n  }\n  long page_size = rows * cols;\n  long num_pages = 1;\n  for (int i = 2; i < t.ndim; i++) num_pages *= t.dims[i];\n\n  for (long p = 0; p < num_pages; p++) {\n    if (t.ndim > 2) {\n      /* Blank line between pages (after the previous slice's trailing\n       * '\\n'). For the very first page there is no leading separator. */\n      if (p > 0) putchar('\\n');\n      /* Outer indices via column-major ind2sub (k2 changes fastest). */\n      long rem = p;\n      fputs(\"(:,:\", stdout);\n      for (int i = 2; i < t.ndim; i++) {\n        long d = t.dims[i];\n        long s = rem % d;\n        rem /= d;\n        printf(\",%ld\", s + 1);\n      }\n      fputs(\") =\\n\\n\", stdout);\n    }\n    mtoc2__disp_real_slice(t.real + p * page_size, rows, cols);\n  }\n}\n",
  "format_double.h": "/* mtoc runtime helper: format a double the same way numbl's\n * `formatNumber` does, into a caller-provided buffer.\n *\n * Used by both scalar and tensor disp so cross-runner output matches\n * numbl byte-for-byte. Kept in its own snippet so disp_double.h and\n * disp_tensor.h can pull it in via the snippet dependency mechanism.\n *\n * Returns the number of characters written (excluding trailing NUL).\n */\n\n#include <stdio.h>\n#include <stdlib.h>\n#include <string.h>\n#include <math.h>\n\nstatic int mtoc2_format_double(char *out, size_t cap, double x) {\n  if (isnan(x)) return snprintf(out, cap, \"NaN\");\n  if (isinf(x)) return snprintf(out, cap, x > 0 ? \"Infinity\" : \"-Infinity\");\n  if (x == 0.0) x = 0.0; /* normalize -0 */\n\n  if (fabs(x) < 1e15 && x == (double)(long long)x) {\n    return snprintf(out, cap, \"%lld\", (long long)x);\n  }\n\n  char buf[64];\n  snprintf(buf, sizeof(buf), \"%.4e\", x);\n  char *e_p = strchr(buf, 'e');\n  if (!e_p) return snprintf(out, cap, \"%s\", buf);\n  int dec_exp = atoi(e_p + 1);\n\n  if (dec_exp < -6 || dec_exp >= 5) {\n    /* Scientific. Strip trailing zeros from mantissa, drop leading\n       zeros from the exponent, but keep its sign. */\n    char *m_end = e_p - 1;\n    while (m_end > buf && *m_end == '0') m_end--;\n    if (m_end >= buf && *m_end == '.') m_end--;\n    char *exp_p = e_p + 1;\n    char sign = '+';\n    if (*exp_p == '+' || *exp_p == '-') { sign = *exp_p; exp_p++; }\n    while (*exp_p == '0' && *(exp_p + 1) != '\\0') exp_p++;\n    return snprintf(out, cap, \"%.*se%c%s\",\n                    (int)(m_end - buf + 1), buf, sign, exp_p);\n  }\n\n  int frac_digits = 4 - dec_exp;\n  if (frac_digits < 0) frac_digits = 0;\n  snprintf(buf, sizeof(buf), \"%.*f\", frac_digits, x);\n  if (strchr(buf, '.')) {\n    size_t len = strlen(buf);\n    while (len > 0 && buf[len - 1] == '0') len--;\n    if (len > 0 && buf[len - 1] == '.') len--;\n    buf[len] = '\\0';\n  }\n  return snprintf(out, cap, \"%s\", buf);\n}\n",
  "length.h": "/* mtoc runtime helper: MATLAB's `length(t)` on a multi-element tensor.\n *\n * Returns the size of the largest axis as a double, or 0.0 if any axis\n * has length 0. Mirrors MATLAB/numbl semantics. Scalar args don't reach\n * this helper — codegen emits the literal `1.0` directly because the C\n * arg is a bare `double`, not an `mtoc2_tensor_t`.\n */\n\nstatic double mtoc2_length(mtoc2_tensor_t t) {\n  long max = 0;\n  for (int i = 0; i < t.ndim; i++) {\n    if (t.dims[i] == 0) return 0.0;\n    if (t.dims[i] > max) max = t.dims[i];\n  }\n  return (double)max;\n}\n",
  "loop_count.h": "/* mtoc2 runtime helper: compute the iteration count for a numbl-style\n * `start : step : end` range as a non-negative `long`.\n *\n * Mirrors numbl's `makeRangeTensor` formula\n * (`Math.max(0, Math.floor((end - start) / step + 1 + 1e-10))`) so\n * that float-imprecision ranges like `0:0.1:0.3` produce the same 4\n * elements both runners. The naive `floor((e-s)/step) + 1` would give\n * 3 because `(0.3 - 0) / 0.1` evaluates to 2.99999999..., one ulp\n * below 3. The `+ 1e-10` cushion is small enough that mathematically\n * non-integer quotients still floor down (the cushion only matters\n * within an ulp of an integer).\n *\n * `step == 0` short-circuits to an empty range — division-by-zero on\n * IEEE doubles would give ±Inf, then `floor(±Inf) + 1` is ±Inf, and\n * the `(long)` cast on Inf is undefined. The early return matches\n * numbl, which also treats step == 0 as empty.\n *\n * The same formula appears at every range-emitting codegen site\n * (single-slot slice reads, multi-slot slice setup, slice range writes,\n * MakeRange, and the For loop); routing through one helper centralizes\n * the cast and protects against undefined behavior when `floor(...)`\n * returns a value outside the `long` range.\n *\n * Returns `0` on:\n *   - step == 0\n *   - non-finite floor result (NaN — e.g. start/end NaN)\n *   - empty range (negative count)\n *   - count that doesn't fit in `long` (clamped rather than aborting:\n *     the user gets an empty range, which is the safest fallback\n *     under static translation — a 1e19-iteration loop is almost\n *     certainly a typo).\n */\n\n#include <limits.h>\n#include <math.h>\n\nstatic long mtoc2_loop_count(double start, double end, double step) {\n  if (step == 0.0) return 0;\n  double n = floor((end - start) / step + 1.0 + 1e-10);\n  if (!isfinite(n)) return 0;\n  if (n <= 0.0) return 0;\n  /* `(long)n` is undefined when n > LONG_MAX. Compare in double\n   * space to keep the guard well-defined. */\n  if (n > (double)LONG_MAX) return 0;\n  return (long)n;\n}\n",
  "numel.h": "/* mtoc runtime helper: MATLAB's `numel(t)` on a multi-element tensor.\n *\n * Returns the product of the axis sizes as a double. Scalar args don't\n * reach this helper — codegen emits the literal `1.0` directly because\n * the C arg is a bare `double`, not an `mtoc2_tensor_t`.\n */\n\nstatic double mtoc2_numel(mtoc2_tensor_t t) {\n  long n = 1;\n  for (int i = 0; i < t.ndim; i++) {\n    n *= t.dims[i];\n  }\n  return (double)n;\n}\n",
  "oob.h": "/* mtoc2 runtime helpers: index bounds checks for tensor access.\n *\n * Numbl raises a `RuntimeError(\"Index exceeds array bounds\")` on any\n * out-of-range scalar or slice access; mtoc2 must match — without these\n * checks the emitter would compile to a raw `base.real[off]` access\n * that silently reads/writes past the buffer.\n *\n * Three helpers cover the access shapes:\n *   - `mtoc2_idx_axis`: per-axis check used by 2-arg or N-arg scalar\n *     indexing (`M(i,j)`, `T(i,j,k)`). Catches `M(4, 1)` on a 2x3\n *     matrix where the linear-total check would erroneously pass.\n *   - `mtoc2_idx_lin`: linear-index check used by 1-arg indexing\n *     (`v(i)`). Validates against numel(t).\n *   - `mtoc2_check_axis_range`: closed-interval check for slice\n *     setup. The slice helpers compute `first`/`last` once at setup\n *     time and call this before iterating.\n *\n * Each helper returns the 0-based offset (or 0-based index) on\n * success and aborts via `mtoc2_oob_abort` on failure. The `loc`\n * string is \"<file>:<offset>\" from the index's source span — formatted\n * by the emitter so the user sees the violating access site.\n *\n * `abort()` is the right exit signal: AddressSanitizer-built binaries\n * already abort on heap-buffer-overflow, so mirroring that gives the\n * same exit code (non-zero, surfaced through execFile in the cross-\n * runner). The cross-runner can't compare stdout when one runner errors,\n * so the unit test suite (vitest) is the home for OOB regression\n * coverage; this helper just makes the runtime error deterministic.\n */\n\n#include <stdio.h>\n#include <stdlib.h>\n\nstatic void mtoc2_oob_abort(\n  const char *loc, int axis, long got, long lo, long hi\n) {\n  if (axis < 0) {\n    fprintf(stderr,\n      \"%s: Index exceeds array bounds (got %ld, valid %ld..%ld)\\n\",\n      loc, got, lo, hi);\n  } else {\n    fprintf(stderr,\n      \"%s: Index in position %d exceeds array bounds (got %ld, valid %ld..%ld)\\n\",\n      loc, axis + 1, got, lo, hi);\n  }\n  /* exit(1) rather than abort(): abort raises SIGABRT, which\n   * spawnSync surfaces as `signal` instead of `status`. The CLI\n   * falls through to `process.exit(run.status ?? 0)` and would\n   * report a successful run. exit(1) gives a clean non-zero\n   * status that the cross-runner sees as \"mtoc2 errored\". */\n  exit(1);\n}\n\nstatic long mtoc2_idx_axis(\n  const mtoc2_tensor_t *t, int axis, long got1, const char *loc\n) {\n  long dim = t->dims[axis];\n  if (got1 < 1 || got1 > dim) mtoc2_oob_abort(loc, axis, got1, 1, dim);\n  return got1 - 1;\n}\n\nstatic long mtoc2_idx_lin(\n  const mtoc2_tensor_t *t, long got1, const char *loc\n) {\n  long total = 1;\n  for (int i = 0; i < t->ndim; i++) total *= t->dims[i];\n  if (got1 < 1 || got1 > total) mtoc2_oob_abort(loc, -1, got1, 1, total);\n  return got1 - 1;\n}\n\nstatic void mtoc2_check_axis_range(\n  const mtoc2_tensor_t *t, int axis, long first1, long last1, const char *loc\n) {\n  long dim = t->dims[axis];\n  if (first1 < 1 || first1 > dim) mtoc2_oob_abort(loc, axis, first1, 1, dim);\n  if (last1 < 1 || last1 > dim) mtoc2_oob_abort(loc, axis, last1, 1, dim);\n}\n\n/* Linear (single-slot) range bounds check: validates against\n * `numel(t)` rather than a per-axis dim. Used by `v(a:b)` /\n * `M(a:b)` style single-slot range slices, where MATLAB semantics\n * are linear-flatten regardless of base shape. */\nstatic void mtoc2_check_linear_range(\n  const mtoc2_tensor_t *t, long first1, long last1, const char *loc\n) {\n  long total = 1;\n  for (int i = 0; i < t->ndim; i++) total *= t->dims[i];\n  if (first1 < 1 || first1 > total) mtoc2_oob_abort(loc, -1, first1, 1, total);\n  if (last1 < 1 || last1 > total) mtoc2_oob_abort(loc, -1, last1, 1, total);\n}\n",
  "range_value.h": "/* mtoc2 runtime helper: i-th element of a numbl-style `start:step:end`\n * range, with snap-to-end on the last element.\n *\n * Mirrors numbl's `makeRangeTensor` step-of-i computation:\n *   - element i is `start + step * i`\n *   - the LAST element (i == count - 1) snaps to exactly `end` when\n *     the computed value is within `|step| * 1e-10` of `end`. Without\n *     the snap, ranges like `0.1:0.1:0.3` produce a last element of\n *     `0.3000000000000000444...`, so `v(end) == 0.3` evaluates to\n *     false even though the user wrote `:0.3`.\n *\n * Used by `mtoc2_tensor_make_range`, slice-read range generation, and\n * the For-loop emitter so every range-yielding site agrees on the\n * snapped values numbl produces.\n */\n\n#include <math.h>\n\nstatic double mtoc2_range_value(\n  double start, double step, double end, long count, long i\n) {\n  double v = start + step * (double)i;\n  if (i == count - 1 && fabs(v - end) < fabs(step) * 1e-10) return end;\n  return v;\n}\n",
  "tensor.h": "/* mtoc tensor runtime: the single C representation for every\n * multi-element tensor mtoc emits.\n *\n * Storage mirrors numbl's split layout — `real` and `imag` are\n * separate Float64 buffers (not interleaved real/imag pairs). For a\n * statically-real tensor, `imag` is NULL: the type system tracks\n * `isComplex` at compile time, so codegen knows up front whether to\n * touch the imag side. There is no runtime branch on `imag != NULL`.\n *\n * Scalars never use this struct — real scalars are bare `double`,\n * complex scalars are `double _Complex`. Anything the type system\n * classifies as multi-element (any axis is not statically 1) gets\n * one `mtoc2_tensor_t` value. The data buffers are column-major to match\n * MATLAB / LAPACK.\n *\n * Shape: `ndim` axes with sizes `dims[0..ndim-1]`. The minimum\n * logical ndim is 2 (matching numbl) — a row vector is `{1, n}` and\n * a column vector is `{n, 1}`. `MTOC2_MAX_NDIM` caps the inline dims\n * array; tensors with more axes than that are unrepresentable in\n * mtoc today (the static type system enforces this at lowering).\n * Keeping `dims` inline preserves the value-typed semantics of\n * `mtoc2_tensor_t` — assign / copy / free do a struct copy and\n * touch only the two heap pointers; the shape rides along for free.\n *\n * Storage is heap-allocated via `mtoc2_alloc` at every assignment\n * site. The struct is predeclared with `real = imag = NULL` and\n * `ndim = 0` (no dims populated); the first assignment populates\n * them, and subsequent reassignments at a different runtime shape\n * free the previous buffers and alloc fresh ones. `free` of the\n * predeclared NULLs is a no-op (well-defined by C), so the cleanup\n * path is uniform for first and subsequent assignments alike.\n *\n * The `MTOC2_RESTRICT` qualifier on the buffer pointers tells the\n * compiler that distinct `mtoc2_tensor_t` values' buffers do not\n * alias each other. It expands to `__restrict__` under GCC/Clang\n * and to nothing on compilers that don't recognize it.\n */\n\n#ifndef MTOC2_RESTRICT\n# if defined(__GNUC__) || defined(__clang__)\n#  define MTOC2_RESTRICT __restrict__\n# else\n#  define MTOC2_RESTRICT\n# endif\n#endif\n\n#ifndef MTOC2_MAX_NDIM\n#define MTOC2_MAX_NDIM 8\n#endif\n\ntypedef struct {\n  double *MTOC2_RESTRICT real;   /* always non-NULL */\n  double *MTOC2_RESTRICT imag;   /* NULL iff the tensor is statically real */\n  int  ndim;\n  long dims[MTOC2_MAX_NDIM];\n} mtoc2_tensor_t;\n",
  "tensor_alloc.h": "/* mtoc runtime helper: allocate an uninitialized real tensor of the\n * given shape. Sets `imag = NULL` (the static-real marker). The\n * returned tensor owns its `real` buffer; caller must release via\n * `mtoc2_tensor_free` (or hand it to `mtoc2_tensor_assign`, which takes\n * ownership).\n *\n * `mtoc2_alloc` aborts on OOM, so the returned struct's `real` is\n * always non-NULL. Used by codegen as the workhorse for elementwise-\n * result construction at every multi-element Assign RHS that isn't a\n * plain tensor literal.\n */\n\n#include <stdint.h>\n#include <stdio.h>\n#include <stdlib.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_alloc(long rows, long cols) {\n  /* MATLAB / numbl clamp negative dim values to 0 (resulting in an\n   * empty tensor) rather than aborting; without this the bare\n   * `(size_t)rows` cast below would wrap a negative `long` to\n   * SIZE_MAX and trigger a spurious \"allocation overflow\" abort. */\n  if (rows < 0) rows = 0;\n  if (cols < 0) cols = 0;\n  mtoc2_tensor_t out;\n  size_t n;\n#if defined(__has_builtin) && __has_builtin(__builtin_mul_overflow)\n  size_t bytes;\n  if (__builtin_mul_overflow((size_t)rows, (size_t)cols, &n) ||\n      __builtin_mul_overflow(n, sizeof(double), &bytes)) {\n    fprintf(stderr,\n      \"mtoc2: tensor allocation overflow (%ldx%ld elements)\\n\", rows, cols);\n    abort();\n  }\n#else\n  if ((size_t)cols != 0 && (size_t)rows > (SIZE_MAX / sizeof(double)) / (size_t)cols) {\n    fprintf(stderr,\n      \"mtoc2: tensor allocation overflow (%ldx%ld elements)\\n\", rows, cols);\n    abort();\n  }\n  n = (size_t)rows * (size_t)cols;\n  size_t bytes = n * sizeof(double);\n#endif\n  out.real = mtoc2_alloc(bytes);\n  out.imag = NULL;\n  out.ndim = 2;\n  out.dims[0] = rows;\n  out.dims[1] = cols;\n  return out;\n}\n",
  "tensor_alloc_nd.h": "/* mtoc2 runtime helper: allocate an uninitialized real tensor with\n * an arbitrary N-D shape.\n *\n * The 2-D fast path lives in `mtoc2_tensor_alloc`; this helper is the\n * variadic N-D sibling that copies `ndim` dim sizes from the caller-\n * supplied `dims` array into the struct.\n *\n * `dims` is consumed read-only — the caller may pass a stack\n * `(long[]){…}` compound literal. The returned tensor owns its\n * `real` buffer; `imag` is NULL (the static-real marker). Aborts\n * on `ndim` exceeding `MTOC2_MAX_NDIM` or on size-math overflow.\n */\n\n#include <stdint.h>\n#include <stdio.h>\n#include <stdlib.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_alloc_nd(int ndim, const long *dims) {\n  if (ndim < 1 || ndim > MTOC2_MAX_NDIM) {\n    /* The rest of the runtime assumes `ndim >= 1` (and codegen enforces\n     * `ndim >= 2`). A zero or negative ndim would skip the dim loop and\n     * leave the tensor in a malformed state with a 1-element default\n     * buffer; better to abort with a clear message. */\n    fprintf(stderr,\n      \"mtoc2: tensor ndim %d out of range [1, %d]\\n\", ndim, MTOC2_MAX_NDIM);\n    abort();\n  }\n  mtoc2_tensor_t out;\n  size_t n = 1;\n  for (int i = 0; i < ndim; i++) {\n    /* MATLAB / numbl clamp negative dim values to 0 (yielding an\n     * empty tensor) rather than aborting. Without this the\n     * `(size_t)dims[i]` cast below wraps a negative `long` to\n     * SIZE_MAX and the very next mul-overflow check fires with a\n     * misleading message. Trigger:\n     *   `n = 0; %!numbl:opaque n; zeros(n - 1, 3);` */\n    long d = dims[i] < 0 ? 0 : dims[i];\n    out.dims[i] = d;\n    size_t new_n;\n#if defined(__has_builtin) && __has_builtin(__builtin_mul_overflow)\n    if (__builtin_mul_overflow(n, (size_t)d, &new_n)) {\n      fprintf(stderr,\n        \"mtoc2: tensor allocation overflow at dim %d (size %ld)\\n\", i, d);\n      abort();\n    }\n#else\n    if ((size_t)d != 0 && n > (SIZE_MAX / sizeof(double)) / (size_t)d) {\n      fprintf(stderr,\n        \"mtoc2: tensor allocation overflow at dim %d (size %ld)\\n\", i, d);\n      abort();\n    }\n    new_n = n * (size_t)d;\n#endif\n    n = new_n;\n  }\n  out.ndim = ndim;\n  size_t bytes;\n#if defined(__has_builtin) && __has_builtin(__builtin_mul_overflow)\n  if (__builtin_mul_overflow(n, sizeof(double), &bytes)) {\n    fprintf(stderr,\n      \"mtoc2: tensor allocation overflow at byte-count (%zu elements)\\n\", n);\n    abort();\n  }\n#else\n  bytes = n * sizeof(double);\n#endif\n  out.real = mtoc2_alloc(bytes);\n  out.imag = NULL;\n  return out;\n}\n",
  "tensor_assign.h": "/* mtoc runtime helper: consume-and-replace tensor assignment.\n *\n * Frees `*lhs`'s current backing buffers and moves `rhs`'s buffers\n * into `*lhs`. The codegen invariant is that every tensor C-expression\n * on an Assign RHS produces a freshly-owned tensor — a literal, a\n * `mtoc2_tensor_copy(...)`, or an elementwise-result built by\n * `mtoc2_tensor_alloc(...)` — so the move (rather than a deep copy\n * here) is sound: there is no caller-side reference to the rhs after\n * the call. After the move `rhs.real`/`rhs.imag` hold the old `*lhs`\n * pointers, but rhs is a temporary in the C sense (it's a value\n * passed by copy) and is discarded immediately.\n *\n * Both frees are unconditional — see `mtoc2_tensor_free` for why\n * that's safe for both real and complex tensors.\n */\n\n#include <stdlib.h>\n\nstatic void mtoc2_tensor_assign(mtoc2_tensor_t *lhs, mtoc2_tensor_t rhs) {\n  free(lhs->real);\n  free(lhs->imag);\n  *lhs = rhs;\n}\n",
  "tensor_copy.h": "/* mtoc runtime helper: deep-copy a real tensor.\n *\n * The returned tensor owns a fresh `real` buffer (memcpy'd from the\n * source); `imag` is NULL since the caller statically knows the\n * source is real. Used by codegen to honor \"copy on every\n * manipulation\" — every tensor-by-name read and every user-function\n * tensor argument is wrapped in this helper, so the receiver always\n * gets an owned tensor.\n */\n\n#include <string.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_copy(mtoc2_tensor_t src) {\n  /* An `mtoc2_tensor_empty()` placeholder (ndim == 0, real == NULL)\n   * can flow into a copy when a conditionally-assigned tensor is read\n   * on a path the conditional didn't fire — return another empty so\n   * downstream consumers see the same placeholder state instead of\n   * `memcpy`ing from NULL. */\n  if (src.ndim == 0 || src.real == NULL) return mtoc2_tensor_empty();\n  /* Struct copy preserves ndim and dims; the heap buffer is\n   * replaced with a fresh allocation of the right total size. */\n  mtoc2_tensor_t out = src;\n  long n = 1;\n  for (int i = 0; i < src.ndim; i++) n *= src.dims[i];\n  out.real = mtoc2_alloc((size_t)n * sizeof(double));\n  out.imag = NULL;\n  memcpy(out.real, src.real, (size_t)n * sizeof(double));\n  return out;\n}\n",
  "tensor_elemwise_real.h": "/* mtoc2 runtime helpers: elementwise binary + unary ops on real\n * tensors. Same-shape only (slope-3 first slice) — general broadcast\n * comes later.\n *\n * Convention in the function names:\n *   `_tt` — both args are tensors of the same shape\n *   `_ts` — tensor + scalar (broadcast scalar across all elements)\n *   `_st` — scalar + tensor (only emitted for non-commutative ops)\n *\n * Every helper returns a freshly-owned tensor — the codegen\n * invariant. The caller hands the result to `mtoc2_tensor_assign`\n * (or to a hoisted temp Assign for in-line uses). No shape check\n * here: same-shape requirement is enforced statically at lowering\n * time, so the runtime trusts its inputs.\n */\n\n#include <stdlib.h>\n\n#define MTOC2_DEFINE_ELEMWISE_TT(name, OP)                                  \\\n  static mtoc2_tensor_t name(mtoc2_tensor_t a, mtoc2_tensor_t b) {          \\\n    long n = 1;                                                             \\\n    for (int i = 0; i < a.ndim; i++) n *= a.dims[i];                        \\\n    mtoc2_tensor_t r;                                                       \\\n    r.real = mtoc2_alloc((size_t)n * sizeof(double));                       \\\n    r.imag = NULL;                                                          \\\n    r.ndim = a.ndim;                                                        \\\n    for (int i = 0; i < a.ndim; i++) r.dims[i] = a.dims[i];                 \\\n    for (long i = 0; i < n; i++) r.real[i] = a.real[i] OP b.real[i];        \\\n    return r;                                                               \\\n  }\n\n#define MTOC2_DEFINE_ELEMWISE_TS(name, OP)                                  \\\n  static mtoc2_tensor_t name(mtoc2_tensor_t a, double s) {                  \\\n    long n = 1;                                                             \\\n    for (int i = 0; i < a.ndim; i++) n *= a.dims[i];                        \\\n    mtoc2_tensor_t r;                                                       \\\n    r.real = mtoc2_alloc((size_t)n * sizeof(double));                       \\\n    r.imag = NULL;                                                          \\\n    r.ndim = a.ndim;                                                        \\\n    for (int i = 0; i < a.ndim; i++) r.dims[i] = a.dims[i];                 \\\n    for (long i = 0; i < n; i++) r.real[i] = a.real[i] OP s;                \\\n    return r;                                                               \\\n  }\n\n#define MTOC2_DEFINE_ELEMWISE_ST(name, OP)                                  \\\n  static mtoc2_tensor_t name(double s, mtoc2_tensor_t b) {                  \\\n    long n = 1;                                                             \\\n    for (int i = 0; i < b.ndim; i++) n *= b.dims[i];                        \\\n    mtoc2_tensor_t r;                                                       \\\n    r.real = mtoc2_alloc((size_t)n * sizeof(double));                       \\\n    r.imag = NULL;                                                          \\\n    r.ndim = b.ndim;                                                        \\\n    for (int i = 0; i < b.ndim; i++) r.dims[i] = b.dims[i];                 \\\n    for (long i = 0; i < n; i++) r.real[i] = s OP b.real[i];                \\\n    return r;                                                               \\\n  }\n\nMTOC2_DEFINE_ELEMWISE_TT(mtoc2_tensor_plus_tt, +)\nMTOC2_DEFINE_ELEMWISE_TT(mtoc2_tensor_minus_tt, -)\nMTOC2_DEFINE_ELEMWISE_TT(mtoc2_tensor_times_tt, *)\nMTOC2_DEFINE_ELEMWISE_TT(mtoc2_tensor_rdivide_tt, /)\n\nMTOC2_DEFINE_ELEMWISE_TS(mtoc2_tensor_plus_ts, +)\nMTOC2_DEFINE_ELEMWISE_TS(mtoc2_tensor_minus_ts, -)\nMTOC2_DEFINE_ELEMWISE_TS(mtoc2_tensor_times_ts, *)\nMTOC2_DEFINE_ELEMWISE_TS(mtoc2_tensor_rdivide_ts, /)\n\n/* Commutative ops (plus, times) reuse `_ts` for `scalar OP tensor`.\n * Non-commutative ops need their own scalar-first flavor. */\nMTOC2_DEFINE_ELEMWISE_ST(mtoc2_tensor_minus_st, -)\nMTOC2_DEFINE_ELEMWISE_ST(mtoc2_tensor_rdivide_st, /)\n\n/* Unary minus — negate every element. */\nstatic mtoc2_tensor_t mtoc2_tensor_uminus(mtoc2_tensor_t a) {\n  long n = 1;\n  for (int i = 0; i < a.ndim; i++) n *= a.dims[i];\n  mtoc2_tensor_t r;\n  r.real = mtoc2_alloc((size_t)n * sizeof(double));\n  r.imag = NULL;\n  r.ndim = a.ndim;\n  for (int i = 0; i < a.ndim; i++) r.dims[i] = a.dims[i];\n  for (long i = 0; i < n; i++) r.real[i] = -a.real[i];\n  return r;\n}\n",
  "tensor_elemwise_real_fn.h": "/* mtoc2 runtime helpers: elementwise binary functions on real\n * tensors (`mod`, `rem`, `atan2`, `hypot`). Same-shape only — same\n * constraint as `tensor_elemwise_real.h` for the infix ops.\n *\n * Each helper returns a freshly-owned tensor. The differences from\n * `tensor_elemwise_real.h`:\n *   - The kernel is `FN(a, b)` (a C function call) rather than\n *     `a OP b` (an infix operator).\n *   - `mod` needs `mtoc2_mod_real` (MATLAB convention: result sign\n *     tracks `b`'s sign), distinct from C's `fmod` (result sign\n *     tracks `a`'s sign).\n *\n * The scalar paths (mod/rem/atan2/hypot on two scalars) call the\n * underlying C function directly via the builtin's `codegenC`; this\n * header only carries the tensor helpers.\n */\n#include <math.h>\n#include <stdlib.h>\n\n/* MATLAB `mod(a, b)`: result has the sign of `b`. `mod(a, 0) = a`. */\nstatic double mtoc2_mod_real(double a, double b) {\n  if (b == 0.0) return a;\n  double r = fmod(a, b);\n  if (r != 0.0 && ((r < 0) != (b < 0))) r += b;\n  return r;\n}\n\n#define MTOC2_DEFINE_ELEMWISE_TT_FN(name, FN)                               \\\n  static mtoc2_tensor_t name(mtoc2_tensor_t a, mtoc2_tensor_t b) {          \\\n    long n = 1;                                                             \\\n    for (int i = 0; i < a.ndim; i++) n *= a.dims[i];                        \\\n    mtoc2_tensor_t r;                                                       \\\n    r.real = mtoc2_alloc((size_t)n * sizeof(double));                       \\\n    r.imag = NULL;                                                          \\\n    r.ndim = a.ndim;                                                        \\\n    for (int i = 0; i < a.ndim; i++) r.dims[i] = a.dims[i];                 \\\n    for (long i = 0; i < n; i++) r.real[i] = FN(a.real[i], b.real[i]);      \\\n    return r;                                                               \\\n  }\n\n#define MTOC2_DEFINE_ELEMWISE_TS_FN(name, FN)                               \\\n  static mtoc2_tensor_t name(mtoc2_tensor_t a, double s) {                  \\\n    long n = 1;                                                             \\\n    for (int i = 0; i < a.ndim; i++) n *= a.dims[i];                        \\\n    mtoc2_tensor_t r;                                                       \\\n    r.real = mtoc2_alloc((size_t)n * sizeof(double));                       \\\n    r.imag = NULL;                                                          \\\n    r.ndim = a.ndim;                                                        \\\n    for (int i = 0; i < a.ndim; i++) r.dims[i] = a.dims[i];                 \\\n    for (long i = 0; i < n; i++) r.real[i] = FN(a.real[i], s);              \\\n    return r;                                                               \\\n  }\n\n#define MTOC2_DEFINE_ELEMWISE_ST_FN(name, FN)                               \\\n  static mtoc2_tensor_t name(double s, mtoc2_tensor_t b) {                  \\\n    long n = 1;                                                             \\\n    for (int i = 0; i < b.ndim; i++) n *= b.dims[i];                        \\\n    mtoc2_tensor_t r;                                                       \\\n    r.real = mtoc2_alloc((size_t)n * sizeof(double));                       \\\n    r.imag = NULL;                                                          \\\n    r.ndim = b.ndim;                                                        \\\n    for (int i = 0; i < b.ndim; i++) r.dims[i] = b.dims[i];                 \\\n    for (long i = 0; i < n; i++) r.real[i] = FN(s, b.real[i]);              \\\n    return r;                                                               \\\n  }\n\nMTOC2_DEFINE_ELEMWISE_TT_FN(mtoc2_tensor_mod_tt,   mtoc2_mod_real)\nMTOC2_DEFINE_ELEMWISE_TT_FN(mtoc2_tensor_rem_tt,   fmod)\nMTOC2_DEFINE_ELEMWISE_TT_FN(mtoc2_tensor_atan2_tt, atan2)\nMTOC2_DEFINE_ELEMWISE_TT_FN(mtoc2_tensor_hypot_tt, hypot)\nMTOC2_DEFINE_ELEMWISE_TT_FN(mtoc2_tensor_power_tt, pow)\n\nMTOC2_DEFINE_ELEMWISE_TS_FN(mtoc2_tensor_mod_ts,   mtoc2_mod_real)\nMTOC2_DEFINE_ELEMWISE_TS_FN(mtoc2_tensor_rem_ts,   fmod)\nMTOC2_DEFINE_ELEMWISE_TS_FN(mtoc2_tensor_atan2_ts, atan2)\nMTOC2_DEFINE_ELEMWISE_TS_FN(mtoc2_tensor_hypot_ts, hypot)\nMTOC2_DEFINE_ELEMWISE_TS_FN(mtoc2_tensor_power_ts, pow)\n\n/* Non-commutative non-fn ops (mod, rem, atan2, power) need scalar-\n * first variants. `hypot` is commutative; the builtin emits `_ts`\n * with swapped operands at scalar-OP-tensor sites. */\nMTOC2_DEFINE_ELEMWISE_ST_FN(mtoc2_tensor_mod_st,   mtoc2_mod_real)\nMTOC2_DEFINE_ELEMWISE_ST_FN(mtoc2_tensor_rem_st,   fmod)\nMTOC2_DEFINE_ELEMWISE_ST_FN(mtoc2_tensor_atan2_st, atan2)\nMTOC2_DEFINE_ELEMWISE_ST_FN(mtoc2_tensor_power_st, pow)\n",
  "tensor_empty.h": "/* mtoc runtime helper: empty/zero-initialized tensor.\n *\n * Returns the canonical \"no buffers, zero shape\" placeholder used to\n * predeclare every tensor variable. Subsequent assignments overwrite\n * the struct via `mtoc2_tensor_assign`, which frees these (NULL)\n * buffers as a no-op and installs the new value.\n */\n\nstatic mtoc2_tensor_t mtoc2_tensor_empty(void) {\n  mtoc2_tensor_t out = { NULL, NULL, 0, {0} };\n  return out;\n}\n",
  "tensor_flip.h": "/* mtoc2 runtime helper: `flip(t, dimIdx)` — return a freshly-owned\n * tensor with `t.real` mirrored along axis `dimIdx` (0-based).\n *\n * Numbl's reference is `flipAlongDim` in\n * `interpreter/builtins/array-manipulation.ts` line ~41. Same\n * column-major slab math: stride = product of dims below the axis,\n * outer = product of dims above. For each outer slab, we walk the\n * axis backwards on the source and forward on the destination,\n * copying `strideDim`-element contiguous blocks.\n *\n * `flipud(t)` lowers to `mtoc2_tensor_flip(t, 0)`; `fliplr(t)` to\n * `mtoc2_tensor_flip(t, 1)`; `flip(t, k)` to\n * `mtoc2_tensor_flip(t, k - 1)`. The `dimIdx` is 0-based at the C\n * boundary so the runtime stays uniform across the three source-\n * level builtins. mtoc2 codegen converts MATLAB's 1-based `k` to\n * 0-based at the call site.\n *\n * Out-of-range `dimIdx` (≥ ndim) is a no-op flip — numbl returns\n * the input unchanged in that case (the \"axis is size 1\" rule). We\n * still allocate a fresh copy so the owned-value invariant holds.\n */\n\n#include <string.h>\n#include <stdlib.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_flip(mtoc2_tensor_t a, long dimIdx) {\n  long total = 1;\n  for (int i = 0; i < a.ndim; i++) total *= a.dims[i];\n  mtoc2_tensor_t r;\n  r.real = mtoc2_alloc((size_t)total * sizeof(double));\n  r.imag = NULL;\n  r.ndim = a.ndim;\n  for (int i = 0; i < a.ndim; i++) r.dims[i] = a.dims[i];\n\n  long axisSize = (dimIdx >= 0 && dimIdx < (long)a.ndim) ? a.dims[dimIdx] : 1;\n  if (axisSize <= 1) {\n    // Nothing to flip — just deep-copy the buffer.\n    if (total > 0) memcpy(r.real, a.real, (size_t)total * sizeof(double));\n    return r;\n  }\n\n  long strideDim = 1;\n  for (long d = 0; d < dimIdx; d++) strideDim *= a.dims[d];\n  long slabSize = strideDim * axisSize;\n  long numOuter = total / slabSize;\n\n  for (long outer = 0; outer < numOuter; outer++) {\n    long base = outer * slabSize;\n    for (long k = 0; k < axisSize; k++) {\n      long srcOff = base + k * strideDim;\n      long dstOff = base + (axisSize - 1 - k) * strideDim;\n      memcpy(\n        r.real + dstOff,\n        a.real + srcOff,\n        (size_t)strideDim * sizeof(double)\n      );\n    }\n  }\n  return r;\n}\n",
  "tensor_free.h": "/* mtoc runtime helper: release a tensor's backing buffers and reset\n * the struct to the empty/zero state.\n *\n * Both `free`s are unconditional. `free(NULL)` is well-defined, so\n * the imag-side free is a no-op for real tensors (where `imag` is\n * always NULL) and a real release for complex tensors. There is no\n * runtime branch on `imag != NULL`. Resetting the struct lets a\n * freed local be safely re-used by `mtoc2_tensor_assign` without\n * leaking. Called at every scope-exit site (end of `main`, end of a\n * function body, every `IRStmt.ReturnFromFunction`).\n */\n\n#include <stdlib.h>\n\nstatic void mtoc2_tensor_free(mtoc2_tensor_t *t) {\n  free(t->real);\n  free(t->imag);\n  t->real = NULL;\n  t->imag = NULL;\n  t->ndim = 0;\n}\n",
  "tensor_from_matrix.h": "/* mtoc runtime helper: build a rows×cols real tensor from a flat\n * column-major data pointer. Codegen reorders the literal's\n * row-major source cells to column-major when it builds the\n * compound-literal array, so layout matches the rest of the runtime.\n */\n\n#include <string.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_from_matrix(\n  const double *data, long rows, long cols\n) {\n  mtoc2_tensor_t out = mtoc2_tensor_alloc(rows, cols);\n  memcpy(out.real, data, (size_t)(rows * cols) * sizeof(double));\n  return out;\n}\n",
  "tensor_from_row.h": "/* mtoc runtime helper: build a 1×n real tensor from a flat data\n * pointer. The caller typically passes a C99 compound literal\n * (`(double[]){1.0, 2.0, 3.0}`), which gives the emitted assignment\n * the same one-line shape as the numbl source.\n */\n\n#include <string.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_from_row(const double *data, long n) {\n  mtoc2_tensor_t out = mtoc2_tensor_alloc(1, n);\n  memcpy(out.real, data, (size_t)n * sizeof(double));\n  return out;\n}\n",
  "tensor_logical_real.h": "/* mtoc2 runtime helpers: elementwise logical ops on real tensors.\n *\n * Same allocate-and-fill pattern as tensor_unary_real_math.h, but the\n * per-element kernel is a logical predicate that returns 0.0 or 1.0.\n *\n * `mtoc2_tensor_not` mirrors numbl's `not(v)` (runtimeOperators.ts):\n * a real-tensor input produces a freshly-owned logical-typed tensor\n * of the same shape with `out[i] = (in[i] == 0.0) ? 1.0 : 0.0`. We\n * carry no separate logical storage flag at the C level — the type\n * system records `elem: \"logical\"` on the result so disp /\n * downstream consumers know how to interpret the doubles.\n */\n#include <stdlib.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_not(mtoc2_tensor_t a) {\n  long n = 1;\n  for (int i = 0; i < a.ndim; i++) n *= a.dims[i];\n  mtoc2_tensor_t r;\n  r.real = mtoc2_alloc((size_t)n * sizeof(double));\n  r.imag = NULL;\n  r.ndim = a.ndim;\n  for (int i = 0; i < a.ndim; i++) r.dims[i] = a.dims[i];\n  for (long i = 0; i < n; i++) r.real[i] = (a.real[i] == 0.0) ? 1.0 : 0.0;\n  return r;\n}\n",
  "tensor_make_range.h": "/* mtoc2 runtime helper: build a freshly-owned 1×N row tensor for a\n * `start : step : end` range used as a value (outside an index slot\n * and outside a for-loop iterable).\n *\n * The count is computed via `mtoc2_loop_count`; the result tensor is\n * allocated via `mtoc2_tensor_alloc_nd` so it lives in the standard\n * owned-tensor lifecycle (assign / copy / free). Caller is expected\n * to consume the result via `mtoc2_tensor_assign(&v, ...)` (or as a\n * fresh function-call arg).\n */\n\nstatic mtoc2_tensor_t mtoc2_tensor_make_range(double start, double step, double end) {\n  long n = mtoc2_loop_count(start, end, step);\n  mtoc2_tensor_t t = mtoc2_tensor_alloc_nd(2, (long[]){1, n});\n  for (long k = 0; k < n; k++) {\n    t.real[k] = mtoc2_range_value(start, step, end, n, k);\n  }\n  return t;\n}\n",
  "tensor_mtimes_real.h": "/* mtoc2 runtime helper: real 2-D matrix multiplication `A * B`.\n *\n * A is m×k, B is k×n; result is m×n, freshly owned. Column-major in,\n * column-major out — A's element at (i, p) lives at `a.real[i + p*m]`;\n * B's element at (p, j) lives at `b.real[p + j*k]`; result at (i, j)\n * lives at `r.real[i + j*m]`.\n *\n * The translate-time check guarantees both inputs are 2-D and\n * `a.dims[1] == b.dims[0]` when both shapes are statically known.\n * When one or both shapes are partly unknown, the check fires at\n * runtime; mismatch aborts with a clear message (mtoc2 doesn't have\n * an exception-throwing channel).\n *\n * The inner-product accumulator runs over the shared dimension k. The\n * loop order (i outermost, then j, with p innermost) traverses A\n * column-by-column on the inside and writes to r column-by-column on\n * the outside, mirroring numbl's `mtimesCore`.\n *\n * The vector-special-cases (column×row outer product, row×column\n * inner product, row×matrix, matrix×column) all reduce to the same\n * triple-loop — no separate fast path.\n */\n\n#include <stdio.h>\n#include <stdlib.h>\n\n/* Scalar-return variant for the 1×k * k×1 inner-product case. The\n * tensor-return helper above always allocates m*n doubles even when\n * m=n=1; this path skips the allocation and just returns the dot\n * product. The translate-time type system classifies a 1×1 result\n * as a scalar (`isMultiElement` returns false), and `mtoc2_disp_double`\n * / scalar consumers need a `double`-typed expression. */\nstatic double mtoc2_tensor_mtimes_real_scalar(mtoc2_tensor_t a,\n                                               mtoc2_tensor_t b) {\n  if (a.ndim != 2 || b.ndim != 2) {\n    fprintf(stderr,\n            \"mtoc2_tensor_mtimes_real_scalar: inputs must be 2-D (got %d-D, %d-D)\\n\",\n            a.ndim, b.ndim);\n    abort();\n  }\n  if (a.dims[0] != 1 || b.dims[1] != 1) {\n    fprintf(stderr,\n            \"mtoc2_tensor_mtimes_real_scalar: scalar-result form requires 1×k * k×1 (got %ld×%ld * %ld×%ld)\\n\",\n            a.dims[0], a.dims[1], b.dims[0], b.dims[1]);\n    abort();\n  }\n  if (a.dims[1] != b.dims[0]) {\n    fprintf(stderr,\n            \"mtoc2_tensor_mtimes_real_scalar: inner-dim mismatch (%ld×%ld * %ld×%ld)\\n\",\n            a.dims[0], a.dims[1], b.dims[0], b.dims[1]);\n    abort();\n  }\n  long k = a.dims[1];\n  double acc = 0.0;\n  for (long p = 0; p < k; p++) {\n    acc += a.real[p] * b.real[p];\n  }\n  return acc;\n}\n\nstatic mtoc2_tensor_t mtoc2_tensor_mtimes_real(mtoc2_tensor_t a,\n                                                mtoc2_tensor_t b) {\n  if (a.ndim != 2 || b.ndim != 2) {\n    fprintf(stderr,\n            \"mtoc2_tensor_mtimes_real: inputs must be 2-D (got %d-D, %d-D)\\n\",\n            a.ndim, b.ndim);\n    abort();\n  }\n  long m = a.dims[0];\n  long k = a.dims[1];\n  long k2 = b.dims[0];\n  long n = b.dims[1];\n  if (k != k2) {\n    fprintf(stderr,\n            \"mtoc2_tensor_mtimes_real: inner-dim mismatch (%ld×%ld * %ld×%ld)\\n\",\n            m, k, k2, n);\n    abort();\n  }\n  mtoc2_tensor_t r;\n  r.real = mtoc2_alloc((size_t)m * (size_t)n * sizeof(double));\n  r.imag = NULL;\n  r.ndim = 2;\n  r.dims[0] = m;\n  r.dims[1] = n;\n  for (long j = 0; j < n; j++) {\n    for (long i = 0; i < m; i++) {\n      double acc = 0.0;\n      for (long p = 0; p < k; p++) {\n        acc += a.real[i + p * m] * b.real[p + j * k];\n      }\n      r.real[i + j * m] = acc;\n    }\n  }\n  return r;\n}\n",
  "tensor_ones_nd.h": "/* mtoc2 runtime helper: build a real N-D tensor filled with ones.\n *\n * Allocates via `mtoc2_tensor_alloc_nd`, then fills the `real` buffer\n * with `1.0` via a plain element loop (`memset` only works for byte\n * patterns; `1.0` is not such a pattern). The returned tensor is\n * freshly owned; `imag` is NULL.\n */\n\nstatic mtoc2_tensor_t mtoc2_tensor_ones_nd(int ndim, const long *dims) {\n  mtoc2_tensor_t out = mtoc2_tensor_alloc_nd(ndim, dims);\n  size_t n = 1;\n  for (int i = 0; i < ndim; i++) n *= (size_t)out.dims[i];\n  for (size_t i = 0; i < n; i++) out.real[i] = 1.0;\n  return out;\n}\n",
  "tensor_ones_square.h": "/* mtoc2 runtime helper: build an n×n real tensor filled with ones.\n *\n * Single-eval companion to `mtoc2_tensor_ones_nd` for the MATLAB\n * `ones(n)` shorthand when `n` is a runtime expression. See the\n * `mtoc2_tensor_zeros_square` header for the rationale.\n */\n\nstatic mtoc2_tensor_t mtoc2_tensor_ones_square(long n) {\n  long dims[2] = {n, n};\n  return mtoc2_tensor_ones_nd(2, dims);\n}\n",
  "tensor_reduce_real.h": "/* mtoc2 runtime helpers: real-tensor reductions.\n *\n * One macro per op generates two helpers:\n *\n *   mtoc2_<name>_all(a)       — reduce every element to a scalar.\n *   mtoc2_<name>_dim(a, dim)  — reduce along the 1-based axis `dim`,\n *                               returning a freshly-owned tensor.\n *\n * The `_dim` template mirrors numbl's `forEachSlice`: compute\n * `before = prod(dims[0..dim-2])`, `axis = dims[dim-1]`,\n * `after = prod(dims[dim..ndim-1])`. Walk the column-major buffer in\n * `(after × before)` fiber order with stride `before` between\n * elements along the reduced axis. Output dims are the input dims\n * with `dims[dim-1] = 1`, then trailing singletons stripped subject\n * to a 2-axis floor (matches the type system's\n * `tensorDoubleFromDims` rule).\n *\n * If `dim > a.ndim` the runtime emits a per-op no-op: every reducer\n * (sum/prod/mean/min/max) copies `a` as-is; the logical reducers\n * (any/all) emit an elementwise cast to {0, 1}. The transfer step\n * already proved the output shape, so this branch only fires when\n * the type-side dim/shape analysis can't fold to AxisAll.\n *\n * Real-only — complex is out of scope. Same-shape and column-major\n * conventions match the rest of mtoc2's tensor runtime.\n */\n\n#include <math.h>\n#include <stdlib.h>\n#include <string.h>\n\n/* Strip trailing singleton axes down to a 2-axis floor. Updates\n * `*ndim` in place; `dims` is the row buffer. */\nstatic void mtoc2__squeeze_trailing(int *ndim, long *dims) {\n  while (*ndim > 2 && dims[*ndim - 1] == 1) {\n    (*ndim)--;\n  }\n}\n\n/* Helper: reduce-all loop for accumulator-based reducers\n * (sum, prod, mean). `INIT` seeds the accumulator; `ACCUM(acc, x)`\n * is a C statement updating `acc`; `FINALIZE(acc, n)` is the final\n * transformation given the count. */\n#define MTOC2_DEFINE_ACCUM_REDUCTION(name, INIT, ACCUM, FINALIZE)             \\\n  static double mtoc2_##name##_all(mtoc2_tensor_t a) {                        \\\n    long n = 1;                                                               \\\n    for (int i = 0; i < a.ndim; i++) n *= a.dims[i];                          \\\n    double acc = (INIT);                                                      \\\n    for (long i = 0; i < n; i++) {                                            \\\n      double x = a.real[i];                                                   \\\n      ACCUM(acc, x);                                                          \\\n    }                                                                         \\\n    return FINALIZE(acc, n);                                                  \\\n  }                                                                           \\\n                                                                              \\\n  static mtoc2_tensor_t mtoc2_##name##_dim(mtoc2_tensor_t a, int dim) {       \\\n    if (dim < 1) {                                                            \\\n      fprintf(stderr, \"mtoc2: \" #name \"_dim: dim must be >= 1 (got %d)\\n\",    \\\n              dim);                                                           \\\n      abort();                                                                \\\n    }                                                                         \\\n    if (dim > a.ndim) {                                                       \\\n      /* No-op axis: output is same shape/data as input (fresh copy). */      \\\n      long total = 1;                                                         \\\n      for (int i = 0; i < a.ndim; i++) total *= a.dims[i];                    \\\n      mtoc2_tensor_t out;                                                     \\\n      out.ndim = a.ndim;                                                      \\\n      for (int i = 0; i < a.ndim; i++) out.dims[i] = a.dims[i];               \\\n      out.real = mtoc2_alloc((size_t)total * sizeof(double));                 \\\n      out.imag = NULL;                                                        \\\n      memcpy(out.real, a.real, (size_t)total * sizeof(double));               \\\n      return out;                                                             \\\n    }                                                                         \\\n    int dimIdx = dim - 1;                                                     \\\n    long axis = a.dims[dimIdx];                                               \\\n    long before = 1;                                                          \\\n    for (int i = 0; i < dimIdx; i++) before *= a.dims[i];                     \\\n    long after = 1;                                                           \\\n    for (int i = dimIdx + 1; i < a.ndim; i++) after *= a.dims[i];             \\\n    long out_total = before * after;                                          \\\n    long out_dims[MTOC2_MAX_NDIM];                                            \\\n    int out_ndim = a.ndim;                                                    \\\n    for (int i = 0; i < a.ndim; i++) out_dims[i] = a.dims[i];                 \\\n    out_dims[dimIdx] = 1;                                                     \\\n    mtoc2__squeeze_trailing(&out_ndim, out_dims);                             \\\n    mtoc2_tensor_t out = mtoc2_tensor_alloc_nd(out_ndim, out_dims);           \\\n    long slab = before * axis;                                                \\\n    for (long outer = 0; outer < after; outer++) {                            \\\n      long slabBase = outer * slab;                                           \\\n      for (long inner = 0; inner < before; inner++) {                         \\\n        double acc = (INIT);                                                  \\\n        for (long k = 0; k < axis; k++) {                                     \\\n          double x = a.real[slabBase + inner + k * before];                   \\\n          ACCUM(acc, x);                                                      \\\n        }                                                                     \\\n        out.real[outer * before + inner] = FINALIZE(acc, axis);               \\\n      }                                                                       \\\n    }                                                                         \\\n    (void)out_total;                                                          \\\n    return out;                                                               \\\n  }\n\n/* Helper: reduce-all loop for min/max. Seed is NaN; first non-NaN\n * element captures, later non-NaN elements compare via CMP.\n * Mirrors numbl's NaN-skip convention. */\n#define MTOC2_DEFINE_MINMAX_REDUCTION(name, CMP)                              \\\n  static double mtoc2_##name##_all(mtoc2_tensor_t a) {                        \\\n    long n = 1;                                                               \\\n    for (int i = 0; i < a.ndim; i++) n *= a.dims[i];                          \\\n    double acc = NAN;                                                         \\\n    for (long i = 0; i < n; i++) {                                            \\\n      double x = a.real[i];                                                   \\\n      if (x != x) continue; /* skip NaN */                                    \\\n      if (acc != acc || (x CMP acc)) acc = x;                                 \\\n    }                                                                         \\\n    return acc;                                                               \\\n  }                                                                           \\\n                                                                              \\\n  static mtoc2_tensor_t mtoc2_##name##_dim(mtoc2_tensor_t a, int dim) {       \\\n    if (dim < 1) {                                                            \\\n      fprintf(stderr, \"mtoc2: \" #name \"_dim: dim must be >= 1 (got %d)\\n\",    \\\n              dim);                                                           \\\n      abort();                                                                \\\n    }                                                                         \\\n    if (dim > a.ndim) {                                                       \\\n      long total = 1;                                                         \\\n      for (int i = 0; i < a.ndim; i++) total *= a.dims[i];                    \\\n      mtoc2_tensor_t out;                                                     \\\n      out.ndim = a.ndim;                                                      \\\n      for (int i = 0; i < a.ndim; i++) out.dims[i] = a.dims[i];               \\\n      out.real = mtoc2_alloc((size_t)total * sizeof(double));                 \\\n      out.imag = NULL;                                                        \\\n      memcpy(out.real, a.real, (size_t)total * sizeof(double));               \\\n      return out;                                                             \\\n    }                                                                         \\\n    int dimIdx = dim - 1;                                                     \\\n    long axis = a.dims[dimIdx];                                               \\\n    long before = 1;                                                          \\\n    for (int i = 0; i < dimIdx; i++) before *= a.dims[i];                     \\\n    long after = 1;                                                           \\\n    for (int i = dimIdx + 1; i < a.ndim; i++) after *= a.dims[i];             \\\n    long out_dims[MTOC2_MAX_NDIM];                                            \\\n    int out_ndim = a.ndim;                                                    \\\n    for (int i = 0; i < a.ndim; i++) out_dims[i] = a.dims[i];                 \\\n    out_dims[dimIdx] = 1;                                                     \\\n    mtoc2__squeeze_trailing(&out_ndim, out_dims);                             \\\n    mtoc2_tensor_t out = mtoc2_tensor_alloc_nd(out_ndim, out_dims);           \\\n    long slab = before * axis;                                                \\\n    for (long outer = 0; outer < after; outer++) {                            \\\n      long slabBase = outer * slab;                                           \\\n      for (long inner = 0; inner < before; inner++) {                         \\\n        double acc = NAN;                                                     \\\n        for (long k = 0; k < axis; k++) {                                     \\\n          double x = a.real[slabBase + inner + k * before];                   \\\n          if (x != x) continue;                                               \\\n          if (acc != acc || (x CMP acc)) acc = x;                             \\\n        }                                                                     \\\n        out.real[outer * before + inner] = acc;                               \\\n      }                                                                       \\\n    }                                                                         \\\n    return out;                                                               \\\n  }\n\n/* Helper: any/all reduction. Short-circuits per fiber.\n * `EMPTY_RESULT` is the value when the reduced fiber is empty:\n *  - any: 0 (no element is nonzero in an empty set)\n *  - all: 1 (vacuously true)\n * `SHORT(acc, x)` updates `acc` if `x` triggers the short-circuit;\n * `done` short-circuits the inner loop once `acc` settles. */\n#define MTOC2_DEFINE_LOGICAL_REDUCTION(name, EMPTY_RESULT, SHORT_BODY)        \\\n  static double mtoc2_##name##_all(mtoc2_tensor_t a) {                        \\\n    long n = 1;                                                               \\\n    for (int i = 0; i < a.ndim; i++) n *= a.dims[i];                          \\\n    if (n == 0) return (double)(EMPTY_RESULT);                                \\\n    double acc = (double)(EMPTY_RESULT);                                      \\\n    for (long i = 0; i < n; i++) {                                            \\\n      double x = a.real[i];                                                   \\\n      SHORT_BODY;                                                             \\\n    }                                                                         \\\n    return acc;                                                               \\\n  }                                                                           \\\n                                                                              \\\n  static mtoc2_tensor_t mtoc2_##name##_dim(mtoc2_tensor_t a, int dim) {       \\\n    if (dim < 1) {                                                            \\\n      fprintf(stderr, \"mtoc2: \" #name \"_dim: dim must be >= 1 (got %d)\\n\",    \\\n              dim);                                                           \\\n      abort();                                                                \\\n    }                                                                         \\\n    if (dim > a.ndim) {                                                       \\\n      /* Numbl's `logicalAlongDim` with `dim > ndims` does an elementwise   \\\n       * cast to logical: each element becomes 1.0 if nonzero else 0.0. */   \\\n      long total = 1;                                                         \\\n      for (int i = 0; i < a.ndim; i++) total *= a.dims[i];                    \\\n      long out_dims[MTOC2_MAX_NDIM];                                          \\\n      int out_ndim = a.ndim;                                                  \\\n      for (int i = 0; i < a.ndim; i++) out_dims[i] = a.dims[i];               \\\n      mtoc2_tensor_t out = mtoc2_tensor_alloc_nd(out_ndim, out_dims);         \\\n      for (long i = 0; i < total; i++) {                                      \\\n        out.real[i] = (a.real[i] != 0.0) ? 1.0 : 0.0;                         \\\n      }                                                                       \\\n      return out;                                                             \\\n    }                                                                         \\\n    int dimIdx = dim - 1;                                                     \\\n    long axis = a.dims[dimIdx];                                               \\\n    long before = 1;                                                          \\\n    for (int i = 0; i < dimIdx; i++) before *= a.dims[i];                     \\\n    long after = 1;                                                           \\\n    for (int i = dimIdx + 1; i < a.ndim; i++) after *= a.dims[i];             \\\n    long out_dims[MTOC2_MAX_NDIM];                                            \\\n    int out_ndim = a.ndim;                                                    \\\n    for (int i = 0; i < a.ndim; i++) out_dims[i] = a.dims[i];                 \\\n    out_dims[dimIdx] = 1;                                                     \\\n    mtoc2__squeeze_trailing(&out_ndim, out_dims);                             \\\n    mtoc2_tensor_t out = mtoc2_tensor_alloc_nd(out_ndim, out_dims);           \\\n    long slab = before * axis;                                                \\\n    for (long outer = 0; outer < after; outer++) {                            \\\n      long slabBase = outer * slab;                                           \\\n      for (long inner = 0; inner < before; inner++) {                         \\\n        double acc = (double)(EMPTY_RESULT);                                  \\\n        for (long k = 0; k < axis; k++) {                                     \\\n          double x = a.real[slabBase + inner + k * before];                   \\\n          SHORT_BODY;                                                         \\\n        }                                                                     \\\n        out.real[outer * before + inner] = acc;                               \\\n      }                                                                       \\\n    }                                                                         \\\n    return out;                                                               \\\n  }\n\n/* Identity finalizer (sum, prod): pass the accumulator through. */\n#define MTOC2_FIN_ID(acc, n) (acc)\n/* Mean finalizer: divide by element count. Empty fiber → 0/0 = NaN. */\n#define MTOC2_FIN_MEAN(acc, n) ((double)(acc) / (double)(n))\n\n/* Accumulator-statement macros. Wrapped in `do {} while(0)` to keep\n * them safe inside any single-statement context the templates use. */\n#define MTOC2_ACC_SUM(acc, x) do { (acc) += (x); } while (0)\n#define MTOC2_ACC_PROD(acc, x) do { (acc) *= (x); } while (0)\n\nMTOC2_DEFINE_ACCUM_REDUCTION(sum, 0.0, MTOC2_ACC_SUM, MTOC2_FIN_ID)\nMTOC2_DEFINE_ACCUM_REDUCTION(prod, 1.0, MTOC2_ACC_PROD, MTOC2_FIN_ID)\nMTOC2_DEFINE_ACCUM_REDUCTION(mean, 0.0, MTOC2_ACC_SUM, MTOC2_FIN_MEAN)\n\nMTOC2_DEFINE_MINMAX_REDUCTION(min, <)\nMTOC2_DEFINE_MINMAX_REDUCTION(max, >)\n\nMTOC2_DEFINE_LOGICAL_REDUCTION(any, 0,\n  if (x != 0.0) { acc = 1.0; break; })\nMTOC2_DEFINE_LOGICAL_REDUCTION(all, 1,\n  if (x == 0.0) { acc = 0.0; break; })\n",
  "tensor_reshape_nd.h": "/* mtoc2 runtime helper: reshape a real tensor to an N-D shape.\n *\n * Receives the input tensor by value (`mtoc2_tensor_t`) plus a\n * caller-supplied dim list (`ndim`, `dims`). Allocates a fresh\n * output tensor via `mtoc2_tensor_alloc_nd` and copies the input's\n * column-major buffer wholesale — reshape is a layout reinterpret,\n * so the linear element order is unchanged.\n *\n * Element-count check: the lowerer enforces `prod(input.dims) ==\n * prod(dims)` at translate time when the input shape is statically\n * known. This helper is the fallback when the input shape only\n * appears at runtime (e.g. a tensor function param whose\n * specialization arg type came in without a concrete shape). On\n * mismatch it prints to stderr and aborts, matching numbl's\n * runtime-error surface.\n *\n * Real-only — mtoc2's tensor side is real-only today; the type\n * lattice rejects complex inputs at lowering. The output's `imag`\n * is NULL, set by `mtoc2_tensor_alloc_nd`.\n */\n\n#include <string.h>\n#include <stdio.h>\n#include <stdlib.h>\n\nstatic mtoc2_tensor_t mtoc2_reshape_nd(\n    mtoc2_tensor_t in, int ndim, const long *dims) {\n  size_t in_total = 1;\n  for (int i = 0; i < in.ndim; i++) in_total *= (size_t)in.dims[i];\n  size_t out_total = 1;\n  for (int i = 0; i < ndim; i++) out_total *= (size_t)dims[i];\n  if (in_total != out_total) {\n    fprintf(stderr,\n      \"mtoc2: reshape: number of elements must not change \"\n      \"(in=%zu, out=%zu)\\n\", in_total, out_total);\n    abort();\n  }\n  mtoc2_tensor_t out = mtoc2_tensor_alloc_nd(ndim, dims);\n  if (out_total > 0)\n    memcpy(out.real, in.real, out_total * sizeof(double));\n  return out;\n}\n",
  "tensor_size.h": "/* mtoc2 runtime helper: `size(t)` — returns a freshly-owned 1×ndim\n * row tensor whose elements are the input's dim sizes as doubles.\n * MATLAB / numbl semantics: scalars and vectors return at least a\n * 2-element row (the type system already pads to ndim ≥ 2; this\n * helper just copies dims[] into a row vector).\n *\n * For `size(t, k)` mtoc2 emits a scalar `(double)t.dims[k-1]` inline\n * — no runtime helper needed for that form.\n */\n\n#include <stdlib.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_size_row(mtoc2_tensor_t a) {\n  long n = a.ndim;\n  mtoc2_tensor_t r;\n  r.real = mtoc2_alloc((size_t)n * sizeof(double));\n  r.imag = NULL;\n  r.ndim = 2;\n  r.dims[0] = 1;\n  r.dims[1] = n;\n  for (long i = 0; i < n; i++) r.real[i] = (double)a.dims[i];\n  return r;\n}\n",
  "tensor_transpose.h": "/* mtoc2 runtime helper: real-tensor non-conjugate transpose for 2-D\n * inputs. Returns a freshly-owned tensor with `dims` swapped. The\n * 2-D restriction is enforced at lowering; by the time this helper\n * runs, `a.ndim` is always 2.\n *\n * Column-major in, column-major out. Source `a` has shape (m × n);\n * destination has shape (n × m). Source element at (sr, sc) lives at\n * `a.real[sr + sc*m]`; destination element at (sc, sr) — the transpose\n * mapping — lives at `out.real[sc + sr*n]`. The inner loop walks the\n * source's column-major buffer linearly to keep the read stride\n * unit-stride.\n *\n * For complex support (not yet a thing in mtoc2), the conjugate\n * variant would negate `a.imag` while copying; the non-conjugate\n * variant just copies. Mirrors numbl's `transposeCore` in\n * `helpers/arithmetic.ts`.\n */\n\n#include <stdlib.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_transpose(mtoc2_tensor_t a) {\n  long m = a.dims[0];\n  long n = a.dims[1];\n  mtoc2_tensor_t r;\n  r.real = mtoc2_alloc((size_t)m * (size_t)n * sizeof(double));\n  r.imag = NULL;\n  r.ndim = 2;\n  r.dims[0] = n;\n  r.dims[1] = m;\n  for (long sc = 0; sc < n; sc++) {\n    for (long sr = 0; sr < m; sr++) {\n      r.real[sc + sr * n] = a.real[sr + sc * m];\n    }\n  }\n  return r;\n}\n",
  "tensor_unary_real_math.h": "/* mtoc2 runtime helpers: elementwise unary math on real tensors.\n *\n * Allocate-and-fill pattern matching `tensor_elemwise_real.h`. The\n * fresh tensor inherits the input's shape; the loop applies the C\n * <math.h> function elementwise.\n *\n * `sign` has no direct <math.h> equivalent — we provide\n * `mtoc2_signum` inline. `round` uses C99's `round()` (half-away-\n * from-zero, matching MATLAB) via the `mtoc2_round_half_away`\n * wrapper.\n */\n#include <math.h>\n#include <stdlib.h>\n\n/* MATLAB convention: round(-1.5) = -2 (away from zero). C99's round()\n * is half-away-from-zero per the spec, which matches. Wrapped for\n * symmetry with the rest of the helpers (and to give the codegen a\n * single C symbol to call regardless of compiler quirks). */\nstatic double mtoc2_round_half_away(double x) {\n  return round(x);\n}\n\n/* signum(x) ∈ {-1, 0, 1, NaN}. Matches JS `Math.sign`:\n *   - NaN → NaN (any comparison with NaN is false, so a naive\n *     positive/negative test would silently return 0).\n *   - -0 → 0 (handled by the equality-to-zero fall-through). */\nstatic double mtoc2_signum(double x) {\n  if (isnan(x)) return x;\n  if (x > 0) return 1.0;\n  if (x < 0) return -1.0;\n  return 0.0;\n}\n\n#define MTOC2_DEFINE_UNARY_MATH(name, FN)                                   \\\n  static mtoc2_tensor_t name(mtoc2_tensor_t a) {                            \\\n    long n = 1;                                                             \\\n    for (int i = 0; i < a.ndim; i++) n *= a.dims[i];                        \\\n    mtoc2_tensor_t r;                                                       \\\n    r.real = mtoc2_alloc((size_t)n * sizeof(double));                       \\\n    r.imag = NULL;                                                          \\\n    r.ndim = a.ndim;                                                        \\\n    for (int i = 0; i < a.ndim; i++) r.dims[i] = a.dims[i];                 \\\n    for (long i = 0; i < n; i++) r.real[i] = FN(a.real[i]);                 \\\n    return r;                                                               \\\n  }\n\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_cos,   cos)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_sin,   sin)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_tan,   tan)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_atan,  atan)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_exp,   exp)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_log,   log)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_log2,  log2)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_log10, log10)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_sqrt,  sqrt)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_abs,   fabs)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_floor, floor)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_ceil,  ceil)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_fix,   trunc)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_round, mtoc2_round_half_away)\nMTOC2_DEFINE_UNARY_MATH(mtoc2_tensor_sign,  mtoc2_signum)\n",
  "tensor_zeros_nd.h": "/* mtoc2 runtime helper: build a real N-D tensor filled with zeros.\n *\n * Allocates via `mtoc2_tensor_alloc_nd`, then zero-fills the `real`\n * buffer with `memset`. The returned tensor is freshly owned;\n * `imag` is NULL.\n */\n\n#include <string.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_zeros_nd(int ndim, const long *dims) {\n  mtoc2_tensor_t out = mtoc2_tensor_alloc_nd(ndim, dims);\n  size_t n = 1;\n  for (int i = 0; i < ndim; i++) n *= (size_t)out.dims[i];\n  memset(out.real, 0, n * sizeof(double));\n  return out;\n}\n",
  "tensor_zeros_square.h": "/* mtoc2 runtime helper: build an n×n real tensor filled with zeros.\n *\n * Single-eval companion to `mtoc2_tensor_zeros_nd` for the MATLAB\n * `zeros(n)` shorthand when `n` is a runtime expression. Taking the\n * dim in a function parameter guarantees the caller-side expression\n * is evaluated exactly once — placing the same C expression in both\n * slots of a compound literal would re-evaluate it (broken for any\n * side-effecting source like `zeros(myfun())`).\n */\n\nstatic mtoc2_tensor_t mtoc2_tensor_zeros_square(long n) {\n  long dims[2] = {n, n};\n  return mtoc2_tensor_zeros_nd(2, dims);\n}\n",
  "tictoc.h": "/* mtoc2 runtime helper: tic / toc wall-clock timing.\n *\n * State is a single static double holding the most recent tic time\n * (seconds since the CLOCK_MONOTONIC epoch). MATLAB and numbl share\n * this \"one global timer\" semantics — `tic` resets it, `toc` reads\n * the delta. No handle form (`t0 = tic; toc(t0)`) in v1.\n *\n * Wall-clock time uses POSIX clock_gettime(CLOCK_MONOTONIC), which\n * gives nanosecond resolution on Linux and macOS, never goes\n * backwards, and isn't affected by NTP adjustments. Windows is not\n * a target; if it ever becomes one, swap in QueryPerformanceCounter\n * here behind an #ifdef.\n *\n * Output format for the bare-`toc` print form mirrors numbl's\n * `\"Elapsed time is %.6f seconds.\\n\"` exactly so the cross-runner's\n * masking regex (see scripts/run_test_scripts.ts) treats both sides\n * as equivalent.\n */\n\n#include <stdio.h>\n#include <time.h>\n\nstatic double mtoc2_tic_seconds = 0.0;\n\nstatic double mtoc2_now_seconds(void) {\n  struct timespec ts;\n  clock_gettime(CLOCK_MONOTONIC, &ts);\n  return (double)ts.tv_sec + (double)ts.tv_nsec / 1e9;\n}\n\nstatic double mtoc2_tic(void) {\n  mtoc2_tic_seconds = mtoc2_now_seconds();\n  return mtoc2_tic_seconds;\n}\n\nstatic double mtoc2_toc(void) {\n  return mtoc2_now_seconds() - mtoc2_tic_seconds;\n}\n\nstatic void mtoc2_toc_print(void) {\n  double elapsed = mtoc2_toc();\n  printf(\"Elapsed time is %.6f seconds.\\n\", elapsed);\n}\n",
};
